import{_ as s,o as a,c as n,ai as i}from"./chunks/framework.DIUhWiTt.js";const h=JSON.parse('{"title":"Harvesting Passwords from Usual Spots","description":"","frontmatter":{},"headers":[],"relativePath":"notas/cheatsheet/3.escalada_de_privilegios/2.windows/otros/2.harvesting-passwords-from-usual-spots.md","filePath":"notas/cheatsheet/3.escalada_de_privilegios/2.windows/otros/2.harvesting-passwords-from-usual-spots.md"}'),o={name:"notas/cheatsheet/3.escalada_de_privilegios/2.windows/otros/2.harvesting-passwords-from-usual-spots.md"};function r(t,e,l,d,c,p){return a(),n("div",null,[...e[0]||(e[0]=[i(`<h1 id="harvesting-passwords-from-usual-spots" tabindex="-1">Harvesting Passwords from Usual Spots <a class="header-anchor" href="#harvesting-passwords-from-usual-spots" aria-label="Permalink to “Harvesting Passwords from Usual Spots”">​</a></h1><p>La forma más sencilla de obtener acceso a otro usuario es recopilar credenciales de una máquina comprometida. Estas credenciales podrían existir por muchas razones, incluido un usuario descuidado que las deja en archivos de texto sin formato; o incluso almacenado por algún software como navegadores o clientes de correo electrónico.</p><p>Esta tarea presentará algunos lugares conocidos para buscar contraseñas en un sistema Windows.</p><h3 id="unattended-windows-installations" tabindex="-1">Unattended Windows Installations <a class="header-anchor" href="#unattended-windows-installations" aria-label="Permalink to “Unattended Windows Installations”">​</a></h3><p>Al instalar Windows en una gran cantidad de hosts, los administradores pueden usar los Servicios de implementación de Windows, que permiten implementar una única imagen del sistema operativo en varios hosts a través de la red. Este tipo de instalaciones se denominan instalaciones desatendidas porque no requieren la interacción del usuario. Dichas instalaciones requieren el uso de una cuenta de administrador para realizar la configuración inicial, que podría terminar almacenándose en la máquina en las siguientes ubicaciones:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>- C:\\Unattend.xml</span></span>
<span class="line"><span>- C:\\Windows\\Panther\\Unattend.xml</span></span>
<span class="line"><span>- C:\\Windows\\Panther\\Unattend\\Unattend.xml</span></span>
<span class="line"><span>- C:\\Windows\\system32\\sysprep.inf</span></span>
<span class="line"><span>- C:\\Windows\\system32\\sysprep\\sysprep.xml</span></span></code></pre></div><p>Como parte de estos archivos, es posible que encuentre credenciales:</p><div class="language-shell-session"><button title="Copy Code" class="copy"></button><span class="lang">shell-session</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>&lt;Credentials&gt;</span></span>
<span class="line"><span>    &lt;Username&gt;Administrator&lt;/Username&gt;</span></span>
<span class="line"><span>    &lt;Domain&gt;thm.local&lt;/Domain&gt;</span></span>
<span class="line"><span>    &lt;Password&gt;MyPassword123&lt;/Password&gt;</span></span>
<span class="line"><span>&lt;/Credentials&gt;</span></span></code></pre></div><h3 id="powershell-history" tabindex="-1">Powershell History <a class="header-anchor" href="#powershell-history" aria-label="Permalink to “Powershell History”">​</a></h3><p>Cada vez que un usuario ejecuta un comando usando Powershell, se almacena en un archivo que guarda una memoria de los comandos anteriores. Esto es útil para repetir rápidamente comandos que ha utilizado antes. Si un usuario ejecuta un comando que incluye una contraseña directamente como parte de la línea de comando de Powershell, luego podrá recuperarla usando el siguiente comando desde un <code>cmd.exe</code>mensaje:</p><div class="language-shell-session"><button title="Copy Code" class="copy"></button><span class="lang">shell-session</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>type %userprofile%\\AppData\\Roaming\\Microsoft\\Windows\\PowerShell\\PSReadline\\ConsoleHost_history.txt</span></span></code></pre></div><p><strong>Nota:</strong> El comando anterior solo funcionará desde cmd.exe, ya que Powershell no lo reconocerá <code>%userprofile%</code>como una variable de entorno. Para leer el archivo desde Powershell, deberá reemplazarlo <code>%userprofile%</code>con <code>$Env:userprofile</code>.</p><h3 id="saved-windows-credentials" tabindex="-1">Saved Windows Credentials <a class="header-anchor" href="#saved-windows-credentials" aria-label="Permalink to “Saved Windows Credentials”">​</a></h3><p>Windows nos permite utilizar las credenciales de otros usuarios. Esta función también brinda la opción de guardar estas credenciales en el sistema. El siguiente comando enumerará las credenciales guardadas:</p><div class="language-shell-session"><button title="Copy Code" class="copy"></button><span class="lang">shell-session</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>cmdkey /list</span></span></code></pre></div><p>Si bien no puede ver las contraseñas reales, si nota alguna credencial que valga la pena probar, puede usarla con el <code>runas</code> comando y la <code>/savecred</code> opción, como se ve a continuación</p><div class="language-shell-session"><button title="Copy Code" class="copy"></button><span class="lang">shell-session</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>runas /savecred /user:admin cmd.exe</span></span></code></pre></div><h3 id="iis-configuration" tabindex="-1">IIS Configuration <a class="header-anchor" href="#iis-configuration" aria-label="Permalink to “IIS Configuration”">​</a></h3><p>Internet Information Services (IIS) es el servidor web predeterminado en las instalaciones de Windows. La configuración de sitios web en IIS se almacena en un archivo llamado <code>web.config</code>y puede almacenar contraseñas para bases de datos o mecanismos de autenticación configurados. Dependiendo de la versión instalada de IIS, podemos encontrar web.config en una de las siguientes ubicaciones:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>- C:\\inetpub\\wwwroot\\web.config</span></span>
<span class="line"><span>- C:\\Windows\\Microsoft.NET\\Framework64\\v4.0.30319\\Config\\web.config</span></span></code></pre></div><p>A continuación se muestra una forma rápida de encontrar cadenas de conexión de bases de datos en el archivo:</p><div class="language-shell-session"><button title="Copy Code" class="copy"></button><span class="lang">shell-session</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>type C:\\Windows\\Microsoft.NET\\Framework64\\v4.0.30319\\Config\\web.config | findstr connectionString</span></span></code></pre></div><h3 id="retrieve-credentials-from-software-putty" tabindex="-1">Retrieve Credentials from Software: PuTTY <a class="header-anchor" href="#retrieve-credentials-from-software-putty" aria-label="Permalink to “Retrieve Credentials from Software: PuTTY”">​</a></h3><p>PuTTY es un cliente SSH que se encuentra comúnmente en sistemas Windows. En lugar de tener que especificar los parámetros de una conexión cada vez, los usuarios pueden almacenar sesiones donde la IP, el usuario y otras configuraciones se pueden almacenar para su uso posterior. Si bien PuTTY no permitirá a los usuarios almacenar su contraseña SSH, almacenará configuraciones de proxy que incluyen credenciales de autenticación de texto sin cifrar.</p><p>Para recuperar las credenciales de proxy almacenadas, puede buscar ProxyPassword en la siguiente clave de registro con el siguiente comando:</p><div class="language-shell-session"><button title="Copy Code" class="copy"></button><span class="lang">shell-session</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>reg query HKEY_CURRENT_USER\\Software\\SimonTatham\\PuTTY\\Sessions\\ /f &quot;Proxy&quot; /s</span></span></code></pre></div><p><strong>Nota:</strong> Simon Tatham es el creador de PuTTY (y su nombre es parte de la ruta), no el nombre de usuario cuya contraseña recuperamos. El nombre de usuario del proxy almacenado también debería ser visible después de ejecutar el comando anterior.</p><p>Así como PuTTY almacena credenciales, cualquier software que almacene contraseñas, incluidos navegadores, clientes de correo electrónico, clientes FTP , clientes SSH, software VNC y otros, tendrá métodos para recuperar cualquier contraseña que el usuario haya guardado.</p>`,28)])])}const g=s(o,[["render",r]]);export{h as __pageData,g as default};
